-- Add insert/update policies for tables and zones
create policy "Allow all inserts" on tables for insert with check (true);
create policy "Allow all updates" on tables for update using (true);
create policy "Allow all updates" on zones for update using (true);

-- Expand grid to 10x8
UPDATE zones SET grid_cols = 10, grid_rows = 8 
WHERE id = '00000000-0000-0000-0000-000000002001';

